         Assert.StartsWith("$", result);
     }

     [TestMethod]
     public void FormatCurrency_EuroSymbol_StartsWithEuro()
     {
         var result = _formatter.FormatCurrency(19.99m, "€");

         Assert.StartsWith("€", result);
     }

